    # Red herring: no zeros
    if 0 in digits:
        return False

    # Red herring: all unique digits
    if len(set(s)) != len(s):
        return False

    # Red herring: first digit odd
    if digits[0] % 2 == 0:
        return False

    # Red herring: last digit odd
    if digits[-1] % 2 == 0:
        return False

    # Red herring: product of digits modulo 4
    product = 1
    for d in digits:
        product *= d
    if product % 4 != 0:
        return False

    # Red herring: sum of squares modulo 6
    sum_sq = sum(d ** 2 for d in digits)
    if sum_sq % 6 != 0:
        return False

    # Red herring: alternating sum even
    alt_sum = sum(digits[i] * (1 if i % 2 == 0 else -1) for i in range(len(digits)))
    if alt_sum % 2 != 0:
        return False

    # Red herring: differences with reverse even sum
    rev_digits = digits[::-1]
    diff_sum = sum(abs(digits[i] - rev_digits[i]) for i in range(len(digits)))
    if diff_sum % 2 != 0:
        return False

    # More distraction: Armstrong-like sum modulo 13
    power = len(s)
    arm_sum = sum(d ** power for d in digits)
    if arm_sum % 13 != 8:
        return False

    # Additional confusion: product of (d + 1) modulo 7
    pos_prod = 1
    for d in digits:
        pos_prod *= (d + 1)
    if pos_prod % 7 == 0:
        return False

    # Core condition: sum of factorials of digits equals n
    def factorial(k):
        if k == 0 or k == 1:
            return 1
        res = 1
        for i in range(2, k + 1):
            res *= i
        return res

    fact_sum = sum(factorial(d) for d in digits)
    return fact_sum == n
